INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('fleet-48', 'SS-MYTH-CTDL-CMND-001', 'spaceship', 'Citadel Command', 'You route every business function through a single intelligent command hierarchy — finance, engineering, marketing, legal, HR, sales, support, and operations all coordinated with real-time optimization and autonomous decision-making.', 'Total enterprise intelligence.', 'Ops', 'Mythic', ARRAY['enterprise','mythic','command'], '{}'::jsonb, '{"crew":"24","slots":"24","tier":"MYTHIC"}'::jsonb, '{"caps":["Route every business function through intelligent command hierarchy","Autonomous cross-department optimization with real-time telemetry","Self-healing operations with predictive disruption management"],"crew":[{"id":"n1","type":"agent","label":"Chief Executive","config":{"agentRole":"CEO"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Chief Operations","config":{"agentRole":"COO"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Chief Technology","config":{"agentRole":"CTO"},"rarity":"Legendary"},{"id":"n4","type":"agent","label":"Chief Financial","config":{"agentRole":"CFO"},"rarity":"Legendary"},{"id":"n5","type":"agent","label":"Chief Marketing","config":{"agentRole":"CMO"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"General Counsel","config":{"agentRole":"Legal"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"HR Director","config":{"agentRole":"HR"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"VP Sales","config":{"agentRole":"Sales"},"rarity":"Epic"},{"id":"n9","type":"agent","label":"Support Lead","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Lead Engineer","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n11","type":"agent","label":"Platform Engineer","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n12","type":"agent","label":"Backend Engineer","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n13","type":"agent","label":"Frontend Engineer","config":{"agentRole":"Engineering