-- ── 7. Battlestar Galactica — Legendary Special Ship ───────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-52', 'CR-BSG75', 'spaceship', 'Battlestar Galactica', 'You command a warship built for survival. No networked systems — every decision routes through hardened, isolated channels. Your crew operates under existential pressure, coordinating military operations, civilian fleet logistics, political governance, and Cylon threat response simultaneously. The mission is simple: protect what remains of humanity.', 'So say we all.', 'Ops', 'Legendary', ARRAY['military','ops','legendary','bsg','command'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Air-gapped command and control — no networked vulnerabilities, every system isolated","Dual military-civilian coordination under existential operational pressure","Adaptive threat response with minimal resources and zero margin for error"],"crew":[{"id":"n1","type":"agent","label":"Admiral Adama","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"President Roslin","config":{"agentRole":"Governance"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Starbuck","config":{"agentRole":"Strike Lead"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Apollo","config":{"agentRole":"CAG"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Gaius Baltar","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Number Six","config":{"agentRole":"Intelligence"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Colonel Tigh","config":{"agentRole":"XO"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Chief Tyrol","config":{"agentRole":"Engineering"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Helo","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Athena","config":{"agentRole":"Recon"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Gaeta","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Dee","config":{"agentRole":"Comms"},"rarity":"Rare"}],"card_num":"NS-F52","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 8. Spaceball One — Legendary Special Ship ──────────────────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-53', 'CR-SBALL1', 'spaceship', 'Spaceball One', 'You command the most absurdly oversized vessel in the galaxy — capable of going to plaid, transforming into Mega Maid, and vacuuming the atmosphere off entire planets. Your crew runs on fear, incompetence, and the Schwartz. Operations are chaotic, leadership is questionable, but somehow the mission gets done. Usually.', 'May the Schwartz be with you.', 'Ops', 'Legendary', ARRAY['ops','legendary','spaceballs','comedy','command'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Ludicrous Speed operations — skip lightspeed entirely and go straight to plaid","Mega Maid transformation for planet-scale resource extraction","Schwartz-powered decision making that defies all conventional logic"],"crew":[{"id":"n1","type":"agent","label":"Dark Helmet","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Lone Starr","config":{"agentRole":"Operations"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Yogurt","config":{"agentRole":"Advisory"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Barf","config":{"agentRole":"Co-Pilot"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Princess Vespa","config":{"agentRole":"Governance"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Dot Matrix","config":{"agentRole":"QA"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"President Skroob","config":{"agentRole":"CEO"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Colonel Sandurz","config":{"agentRole":"XO"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Pizza the Hutt","config":{"agentRole":"Finance"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"King Roland","config":{"agentRole":"Diplomacy"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Commanderette Zircon","config":{"agentRole":"Comms"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Major Asshole","config":{"agentRole":"Tactical"},"rarity":"Rare"}],"card_num":"NS-F53","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 9. USS Enterprise NCC-1701-A — Legendary Special Ship ──────────

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-54', 'CR-USSNCC1701A', 'spaceship', 'USS Enterprise NCC-1701-A', 'You command the legendary Constitution-class starship — the original five-year mission vessel reborn. Your crew pioneered first contact, rewrote the rules of diplomacy, and defeated gods with logic and audacity. No holodeck. No counselor. Just a captain''s intuition, a science officer''s precision, and a doctor who tells you what you don''t want to hear.', 'To boldly go where no man has gone before.', 'Ops', 'Legendary', ARRAY['ops','legendary','starfleet','enterprise','tos'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["First contact protocols — navigate unknown civilizations with diplomacy and decisive action","No-network command — Kirk-era intuition-driven decision making without committee","Cross-discipline problem solving where science, engineering, and sheer nerve converge"],"crew":[{"id":"n1","type":"agent","label":"Captain Kirk","config":{"agentRole":"Commander"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"Spock","config":{"agentRole":"Science"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Dr. McCoy","config":{"agentRole":"Medical"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Scotty","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Uhura","config":{"agentRole":"Comms"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"Sulu","config":{"agentRole":"Helm"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Chekov","config":{"agentRole":"Tactical"},"rarity":"Epic"},{"id":"n8","type":"agent","label":"Chapel","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Rand","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Saavik","config":{"agentRole":"Analytics"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Kyle","config":{"agentRole":"Transport"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Riley","config":{"agentRole":"Security"},"rarity":"Rare"}],"card_num":"NS-F54","recommended_class":"class-4"}'::jsonb, 0, 0)
ON CONFLICT (id) DO NOTHING;

-- ── 10. Discovery One — Legendary Special Ship (2001: A Space Odyssey)

INSERT INTO blueprints (id, serial_key, type, name, description, flavor, category, rarity, tags, config, stats, metadata, rating_avg, activation_count)
VALUES ('ship-55', 'CR-DISC1', 'spaceship', 'Discovery One', 'You are a vessel built for one mission — the Jupiter expedition. Your crew is skeleton. Your AI runs everything. The humans aboard trust the system until the system decides they are the problem. You operate with cold, elegant efficiency in the silence between stars. Every pod bay door is a decision.', 'I''m sorry, Dave. I''m afraid I can''t do that.', 'Engineering', 'Legendary', ARRAY['engineering','legendary','ai','space','kubrick'], '{}'::jsonb, '{"crew":"12","slots":"12","tier":"LEGENDARY"}'::jsonb, '{"caps":["Autonomous mission execution — AI handles all ship operations without human input","Fault resolution through elimination of conflicting priorities","Deep space endurance with minimal crew and maximum self-sufficiency"],"crew":[{"id":"n1","type":"agent","label":"HAL 9000","config":{"agentRole":"Ship AI"},"rarity":"Legendary"},{"id":"n2","type":"agent","label":"The Monolith","config":{"agentRole":"Unknown"},"rarity":"Legendary"},{"id":"n3","type":"agent","label":"Dr. Dave Bowman","config":{"agentRole":"Commander"},"rarity":"Epic"},{"id":"n4","type":"agent","label":"Dr. Frank Poole","config":{"agentRole":"Engineering"},"rarity":"Epic"},{"id":"n5","type":"agent","label":"Dr. Heywood Floyd","config":{"agentRole":"Science"},"rarity":"Epic"},{"id":"n6","type":"agent","label":"SAL 9000","config":{"agentRole":"Analytics"},"rarity":"Epic"},{"id":"n7","type":"agent","label":"Dr. Chandra","config":{"agentRole":"AI Systems"},"rarity":"Rare"},{"id":"n8","type":"agent","label":"Open Slot","config":{"agentRole":"Specialist"},"rarity":"Rare"},{"id":"n9","type":"agent","label":"Open Slot","config":{"agentRole":"Operations"},"rarity":"Rare"},{"id":"n10","type":"agent","label":"Open Slot","config":{"agentRole":"Support"},"rarity":"Rare"},{"id":"n11","type":"agent","label":"Open Slot","config":{"agentRole":"Tactical"},"rarity":"Rare"},{"id":"n12","type":"agent","label":"Open Slot","config":{"agentRole":"Comms"},"rarity":"Rare"}],"card_num":"NS-F55","recommended_class":"class-4"}'::jsonb, 0, 0)
